import axios from 'axios';
import type { Project, Communication, File } from '../types';

const api = axios.create({
  baseURL: '/api/taskade',
});

// Projects API
export const projectsApi = {
  getAll: async (): Promise<Project[]> => {
    const response = await api.get('/projects/StSWm4DaeTHoxpFw/nodes');
    return response.data.payload.nodes;
  },

  update: async (id: string, data: Partial<Project['fieldValues']>) => {
    await api.patch(`/projects/StSWm4DaeTHoxpFw/nodes/${id}`, data);
  },
};

// Communications API
export const communicationsApi = {
  getAll: async (): Promise<Communication[]> => {
    const response = await api.get('/projects/Xpy6gkXdWBbZnpAT/nodes');
    return response.data.payload.nodes;
  },

  markAsRead: async (id: string) => {
    await api.patch(`/projects/Xpy6gkXdWBbZnpAT/nodes/${id}`, {
      '/attributes/@read3': 'opt-read'
    });
  },
};

// Files API
export const filesApi = {
  getAll: async (): Promise<File[]> => {
    const response = await api.get('/projects/o2Y68eJy8cc4wsrB/nodes');
    return response.data.payload.nodes;
  },
};

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  type ClientOptions,
  createConversation as createConversationApi,
  sendMessage as sendMessageApi,
} from './client';
import { AgentChatStream } from './stream';
import type { ErrorEvent, MessageState, StreamOptions } from './types';

/**
 * Options for useAgentChat hook
 */
export interface UseAgentChatOptions extends StreamOptions {
  /** Auto-connect stream on mount (default: true) */
  autoConnect?: boolean;
}

/**
 * Return type for useAgentChat hook
 */
export interface UseAgentChatReturn {
  /** Send a message to the conversation */
  sendMessage: (text: string) => Promise<void>;
  /** Array of messages (sorted by creation order) */
  messages: MessageState[];
  /** Whether stream is currently connected */
  isConnected: boolean;
  /** Current error, if any */
  error: Error | null;
  /** Current conversation ID */
  conversationId: string | null;
  /** Create a new conversation (stream stays open, switches to new conversation) */
  createConversation: () => Promise<string>;
  /** Switch to a different conversation (stream stays open) */
  switchConversation: (conversationId: string) => void;
  /** Manually connect the stream (useful when autoConnect is false) */
  connect: () => void;
}

/**
 * React hook for managing agent chat conversation
 *
 * Requires a conversationId to be provided. The stream is opened when conversationId is available
 * and stays open throughout the conversation lifecycle.
 *
 * @param agentId - The agent ID
 * @param conversationId - The conversation ID (required - must be created manually)
 * @param options - Configuration options
 * @returns Chat state and methods
 *
 * @example
 * ```typescript
 * function ChatComponent() {
 *   const [conversationId, setConversationId] = useState<string | null>(null);
 *   const { sendMessage, messages, isConnected } = useAgentChat('agent-456', conversationId);
 *
 *   // Create conversation manually
 *   const handleStartChat = async () => {
 *     const { conversationId: newId } = await createConversation('agent-456');
 *     setConversationId(newId);
 *   };
 *
 *   return (
 *     <div>
 *       {!conversationId && <button onClick={handleStartChat}>Start Chat</button>}
 *       {messages.map(msg => (
 *         <div key={msg.id}>{msg.content}</div>
 *       ))}
 *       <button onClick={() => sendMessage('Hello!')}>Send</button>
 *     </div>
 *   );
 * }
 * ```
 */
export function useAgentChat(
  agentId: string,
  conversationId: string | null,
  options?: UseAgentChatOptions,
): UseAgentChatReturn {
  const [messagesMap, setMessagesMap] = useState<Map<string, MessageState>>(new Map());
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const [currentConversationId, setCurrentConversationId] = useState<string | null>(conversationId);
  const streamRef = useRef<AgentChatStream | null>(null);
  const listenersRef = useRef<Array<() => void>>([]);
  const streamAgentIdRef = useRef<string | null>(null);
  const currentConversationIdRef = useRef<string | null>(conversationId);
  const previousConversationIdRef = useRef<string | null>(conversationId);

  // Sync currentConversationId with prop when prop changes externally
  // This ensures the hook's internal state stays in sync with external prop updates
  useEffect(() => {
    const previousId = previousConversationIdRef.current;
    const newId = conversationId;

    // Clear messages when conversationId changes to a different non-null value
    // This handles the case where the prop changes externally (not via createConversation/switchConversation)
    if (previousId !== newId && newId != null && previousId != null) {
      setMessagesMap(new Map());
      // Also clear stream's message states if stream exists
      if (streamRef.current) {
        streamRef.current.clearMessages();
      }
    }

    setCurrentConversationId(newId);
    currentConversationIdRef.current = newId;
    previousConversationIdRef.current = newId;
  }, [conversationId]);

  // Cleanup on component unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
      }
    };
  }, []);

  // Convert messages map to sorted array
  const messages = useMemo(() => {
    const allMessages = Array.from(messagesMap.values());
    // Sort by message ID (ULID) - ULIDs are lexicographically sortable and encode timestamp
    // This ensures chronological order regardless of message role
    allMessages.sort((a, b) => {
      return a.id.localeCompare(b.id);
    });
    return allMessages;
  }, [messagesMap]);

  // Initialize stream when conversationId is available
  // Uses currentConversationId to ensure we're working with the latest state
  // (which may have been updated by createConversation/switchConversation)
  useEffect(() => {
    // Don't initialize if no conversationId
    if (!currentConversationId) {
      // Clean up existing stream if conversationId is removed
      if (streamRef.current) {
        streamRef.current.clearMessages(); // Clear stream's message states
        streamRef.current.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
        setIsConnected(false);
      }
      // Clear messages when conversation is removed
      setMessagesMap(new Map());
      currentConversationIdRef.current = null;
      return;
    }

    // Update ref to track current conversation ID
    currentConversationIdRef.current = currentConversationId;

    // Clean up previous listeners before setting up new ones
    // This ensures we don't accumulate duplicate listeners when reusing the stream
    listenersRef.current.forEach((unsub) => unsub());
    listenersRef.current = [];

    const unsubscribeFunctions: Array<() => void> = [];
    let isMounted = true;

    // Register cleanup function first to ensure it's available immediately
    // This prevents race conditions where component unmounts before cleanup is registered
    const cleanup = () => {
      isMounted = false;
      unsubscribeFunctions.forEach((unsub) => unsub());
      // Note: We don't disconnect the stream here because:
      // 1. The stream may be reused in the next effect run (when switching conversations)
      // 2. Disconnection is handled when conversationId becomes null (early return above)
      // 3. On component unmount, React will call cleanup, but the stream will be garbage collected
      //    when the ref is cleared by the early return path if conversationId becomes null
    };

    try {
      // Ensure we have valid agentId before creating stream
      // Note: currentConversationId is already validated above (early return if falsy)
      if (!agentId) {
        throw new Error(`Invalid parameters: agentId is required`);
      }

      // Helper function to update messages from stream state
      // Defined inline here since it only uses refs and setState (both stable)
      const updateMessages = () => {
        const currentStream = streamRef.current;
        if (currentStream) {
          setMessagesMap((prev) => {
            const next = new Map(prev);
            // Add/update stream messages (assistant responses)
            for (const [id, streamMsg] of currentStream.messages) {
              // Only update if this is an assistant message (or doesn't exist yet)
              // Preserve user messages - they should never be overwritten by stream
              const existing = prev.get(id);
              if (!existing || existing.role === 'assistant') {
                // Merge with existing to preserve content if stream message is missing it
                // Stream message should have latest content, but fallback to existing as safety
                const mergedMsg: MessageState = {
                  ...existing,
                  ...streamMsg,
                  id, // Ensure ID is preserved
                  role: 'assistant' as const,
                  // Prefer stream message content if it exists and is non-empty, otherwise preserve existing
                  content:
                    typeof streamMsg.content === 'string' && streamMsg.content.length > 0
                      ? streamMsg.content
                      : existing?.content || '',
                };
                next.set(id, mergedMsg);
              }
            }
            return next;
          });
        }
      };

      let stream: AgentChatStream;

      // Check if we need to recreate the stream (agentId changed or stream doesn't exist)
      const existingStream = streamRef.current;
      const agentIdChanged = existingStream && streamAgentIdRef.current !== agentId;

      if (agentIdChanged && existingStream) {
        // AgentId changed - preserve messages from old stream before disconnecting
        // The hook's messagesMap should already have all messages, but we ensure
        // any messages in the stream's state are preserved in the hook's state
        setMessagesMap((prev) => {
          const next = new Map(prev);
          // Preserve any messages from the old stream that aren't already in the map
          for (const [id, streamMsg] of existingStream.messages) {
            if (!next.has(id)) {
              next.set(id, streamMsg);
            } else {
              // If message exists, preserve user messages and merge assistant messages
              const existing = prev.get(id);
              if (existing?.role === 'user') {
                // Keep user message as-is
                continue;
              }
              // Merge assistant messages
              if (existing?.role === 'assistant' || !existing) {
                next.set(id, {
                  ...existing,
                  ...streamMsg,
                  id,
                  role: 'assistant' as const,
                });
              }
            }
          }
          return next;
        });
        // Now disconnect the old stream
        existingStream.disconnect();
        streamRef.current = null;
        streamAgentIdRef.current = null;
      }

      // If stream exists and agentId hasn't changed, update its conversation ID and reuse it
      // We still need to re-register event listeners to ensure fresh closures
      if (streamRef.current && !agentIdChanged) {
        stream = streamRef.current;
        // Update conversation ID if needed - this handles disconnection/reconnection
        stream.setConversationId(currentConversationId);
      } else {
        // Create new stream
        const streamOptions: StreamOptions = {
          baseUrl: options?.baseUrl,
          autoReconnect: options?.autoReconnect ?? true,
          reconnectDelay: options?.reconnectDelay,
          onError: (err) => {
            if (isMounted) {
              setError(err);
            }
            options?.onError?.(err);
          },
        };
        stream = new AgentChatStream(agentId, currentConversationId, streamOptions);
        streamRef.current = stream;
        streamAgentIdRef.current = agentId;
      }

      // Always set up event listeners to ensure fresh closures
      // Even if stream exists, we need to re-register listeners with current closures
      // (isMounted, updateMessages, etc.)

      // Subscribe to events
      // Note: We always re-register listeners even if stream exists to ensure fresh closures
      const unsubscribeOpen = stream.on('open', () => {
        if (isMounted) {
          setIsConnected(true);
          setError(null);
        }
      });
      unsubscribeFunctions.push(unsubscribeOpen);

      const unsubscribeClose = stream.on('close', () => {
        if (isMounted) {
          setIsConnected(false);
        }
      });
      unsubscribeFunctions.push(unsubscribeClose);

      const unsubscribeTextDelta = stream.on('text-delta', () => {
        if (isMounted) {
          updateMessages();
        }
      });
      unsubscribeFunctions.push(unsubscribeTextDelta);

      const unsubscribeFinish = stream.on('finish', () => {
        if (isMounted) {
          updateMessages();
        }
      });
      unsubscribeFunctions.push(unsubscribeFinish);

      const unsubscribeError = stream.on('error', (event: ErrorEvent) => {
        if (isMounted) {
          setError(new Error(event.errorText));
        }
      });
      unsubscribeFunctions.push(unsubscribeError);

      // Store unsubscribe functions for cleanup on next effect run
      listenersRef.current = unsubscribeFunctions;

      // Connect stream if autoConnect is enabled (default: true)
      if (options?.autoConnect !== false) {
        stream.connect();
      }
    } catch (err) {
      if (isMounted) {
        const initError = err instanceof Error ? err : new Error('Failed to initialize chat');
        setError(initError);
        console.error('[useAgentChat] Initialization error:', initError);
      }
    }

    // Return cleanup function
    return cleanup;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    agentId,
    currentConversationId, // Use currentConversationId instead of prop to react to internal updates
    options?.baseUrl,
    options?.autoReconnect,
    options?.reconnectDelay,
    options?.autoConnect,
    options?.onError,
    // Note: updateMessages is defined inline in the effect and only uses refs/setState (stable)
  ]);

  // Send message function
  const sendMessage = useCallback(
    async (text: string) => {
      // Use currentConversationId to ensure we're using the latest state
      const convoId = currentConversationId;
      if (!convoId) {
        throw new Error('No conversation available. Create a conversation first.');
      }

      const clientOptions: ClientOptions = {
        baseUrl: options?.baseUrl,
      };

      try {
        setError(null);
        const response = await sendMessageApi(agentId, convoId, text, clientOptions);

        // Check if conversation is still active before adding message
        // This prevents race condition where conversation switches while API call is pending
        // Use ref to check latest conversation ID (closure value might be stale)
        if (currentConversationIdRef.current !== convoId) {
          // Conversation changed during API call, don't add message (it belongs to old conversation)
          return;
        }

        // Add user message with the messageId from the API response
        const userMessage: MessageState = {
          id: response.messageId,
          content: text,
          isComplete: true,
          role: 'user',
        };
        // Add user message to messages map
        setMessagesMap((prev) => {
          const next = new Map(prev);
          next.set(response.messageId, userMessage);
          return next;
        });
      } catch (err) {
        const sendError = err instanceof Error ? err : new Error('Failed to send message');
        setError(sendError);
        throw sendError;
      }
    },
    [agentId, currentConversationId, options?.baseUrl],
  );

  /**
   * Create a new conversation
   *
   * Creates a new conversation and switches the stream to it. The hook's internal state
   * is updated automatically. If you're managing conversationId as a prop, you should
   * also update it to keep it in sync:
   *
   * @example
   * ```typescript
   * const [conversationId, setConversationId] = useState<string | null>(null);
   * const { createConversation } = useAgentChat(agentId, conversationId);
   *
   * const handleNewChat = async () => {
   *   const newId = await createConversation();
   *   setConversationId(newId); // Update prop to keep it in sync
   * };
   * ```
   *
   * @returns The new conversation ID
   */
  const createConversation = useCallback(async (): Promise<string> => {
    const clientOptions: ClientOptions = {
      baseUrl: options?.baseUrl,
    };
    const { conversationId: newConvoId } = await createConversationApi(agentId, clientOptions);

    // Update internal state first - this will trigger useEffect to reinitialize stream
    setCurrentConversationId(newConvoId);
    currentConversationIdRef.current = newConvoId;
    // Clear messages when switching to new conversation
    setMessagesMap(new Map());

    // If stream exists, update it to the new conversation ID
    // This handles the case where stream was already initialized
    if (streamRef.current) {
      streamRef.current.setConversationId(newConvoId);
    }

    return newConvoId;
  }, [agentId, options?.baseUrl]);

  /**
   * Switch to a different conversation
   *
   * Switches the stream to an existing conversation. The hook's internal state
   * is updated automatically. If you're managing conversationId as a prop, you should
   * also update it to keep it in sync:
   *
   * @example
   * ```typescript
   * const [conversationId, setConversationId] = useState<string | null>(null);
   * const { switchConversation } = useAgentChat(agentId, conversationId);
   *
   * const handleSwitchChat = (existingConvoId: string) => {
   *   switchConversation(existingConvoId);
   *   setConversationId(existingConvoId); // Update prop to keep it in sync
   * };
   * ```
   *
   * @param convoId - The conversation ID to switch to
   */
  const switchConversation = useCallback((convoId: string) => {
    // Update internal state first - this will trigger useEffect to reinitialize stream
    setCurrentConversationId(convoId);
    currentConversationIdRef.current = convoId;
    // Clear messages when switching conversations
    setMessagesMap(new Map());

    // If stream exists, update it to the new conversation ID
    // This handles the case where stream was already initialized
    if (streamRef.current) {
      streamRef.current.setConversationId(convoId);
    }
  }, []);

  /**
   * Manually connect the stream
   *
   * Useful when `autoConnect` is set to `false`. The stream must have a valid
   * conversationId before connecting.
   *
   * @example
   * ```typescript
   * const { connect, conversationId } = useAgentChat(agentId, conversationId, {
   *   autoConnect: false,
   * });
   *
   * // Connect manually after conversation is created
   * const handleStartChat = async () => {
   *   const { conversationId: newId } = await createConversation(agentId);
   *   setConversationId(newId);
   *   // Stream will be initialized but not connected due to autoConnect: false
   *   // Manually connect it
   *   connect();
   * };
   * ```
   */
  const connect = useCallback(() => {
    if (!currentConversationId) {
      throw new Error('Cannot connect: no conversation available. Create a conversation first.');
    }

    if (!streamRef.current) {
      throw new Error('Cannot connect: stream not initialized. Ensure conversationId is provided.');
    }

    streamRef.current.connect();
  }, [currentConversationId]);

  return {
    sendMessage,
    messages,
    isConnected,
    error,
    conversationId: currentConversationId,
    createConversation,
    switchConversation,
    connect,
  };
}

/**
 * Agent Chat SDK for Taskade Genesis
 *
 * Low-level SDK for building AI Agent Chat interfaces in React applications.
 * Provides API client, SSE stream management, and optional React hooks.
 *
 * @example
 * ```typescript
 * // Low-level usage (no React)
 * import { createConversation, sendMessage, AgentChatStream } from '@/lib/agent-chat';
 *
 * // Create conversation manually
 * const { conversationId } = await createConversation(agentId);
 * const stream = new AgentChatStream(agentId, conversationId);
 * stream.on('text-delta', ({ id, delta }) => {
 *   // Handle text updates
 * });
 * stream.connect();
 * await sendMessage(agentId, conversationId, 'Hello!');
 * ```
 *
 * @example
 * ```typescript
 * // React hook usage
 * import { useAgentChat, createConversation } from '@/lib/agent-chat';
 * import { useState } from 'react';
 *
 * function ChatComponent() {
 *   const [conversationId, setConversationId] = useState<string | null>(null);
 *   const { sendMessage, messages, isConnected } = useAgentChat(agentId, conversationId);
 *
 *   // Create conversation manually
 *   const handleStartChat = async () => {
 *     const { conversationId: newId } = await createConversation(agentId);
 *     setConversationId(newId);
 *   };
 *
 *   return (
 *     <div>
 *       {!conversationId && <button onClick={handleStartChat}>Start Chat</button>}
 *       {messages.map(msg => (
 *         <div key={msg.id}>
 *           {msg.role === 'user' ? 'You: ' : 'Agent: '}
 *           {msg.content}
 *           {msg.toolCalls && msg.toolCalls.length > 0 && (
 *             <div>Tool calls: {msg.toolCalls.length}</div>
 *           )}
 *         </div>
 *       ))}
 *       <button onClick={() => sendMessage('Hello!')}>Send</button>
 *     </div>
 *   );
 * }
 * ```
 */

// Core API client (for advanced usage)
export type { ClientOptions } from './client';
export { createConversation, sendMessage } from './client';

// Stream manager (for advanced usage)
export { AgentChatStream } from './stream';

// Types
export type {
  CreateConversationResponse,
  ErrorEvent,
  ErrorHandler,
  FinishEvent,
  FinishHandler,
  MessageState,
  SendMessageResponse,
  StartEvent,
  StreamEvent,
  StreamEventHandler,
  StreamOptions,
  TextDeltaEvent,
  TextDeltaHandler,
  TextEndEvent,
  TextStartEvent,
  ToolCallEndEvent,
  ToolCallState,
  ToolInputAvailableEvent,
  ToolInputDeltaEvent,
  ToolInputStartEvent,
  ToolOutputAvailableEvent,
} from './types';

// React hook (main API)
export type { UseAgentChatOptions, UseAgentChatReturn } from './hooks';
export { useAgentChat } from './hooks';

import { z } from 'zod';

/**
 * SSE Event schemas matching backend AgentPublicConversationMessageStreamResponseSchema
 */
export const StreamEventSchema = z.union([
  z.object({
    type: z.literal('start'),
    messageId: z.string(),
  }),
  z.object({
    type: z.literal('text-start'),
    id: z.string(),
  }),
  z.object({
    type: z.literal('text-delta'),
    id: z.string(),
    delta: z.string(),
  }),
  z.object({
    type: z.literal('text-end'),
    id: z.string(),
  }),
  z.object({
    type: z.literal('tool-input-start'),
    toolCallId: z.string(),
    toolName: z.string(),
    messageId: z.string().optional(),
  }),
  z.object({
    type: z.literal('tool-input-delta'),
    toolCallId: z.string(),
    inputTextDelta: z.string(),
    messageId: z.string().optional(),
  }),
  z.object({
    type: z.literal('tool-input-available'),
    toolCallId: z.string(),
    input: z.unknown(),
    messageId: z.string().optional(),
  }),
  z.object({
    type: z.literal('tool-output-available'),
    toolCallId: z.string(),
    output: z.unknown(),
    messageId: z.string().optional(),
  }),
  z.object({
    type: z.literal('tool-call-end'),
    toolCallId: z.string(),
    messageId: z.string().optional(),
  }),
  z.object({
    type: z.literal('finish'),
  }),
  z.object({
    type: z.literal('error'),
    errorText: z.string(),
  }),
]);

export type StreamEvent = z.infer<typeof StreamEventSchema>;

/**
 * Specific event types for type narrowing
 */
export type StartEvent = Extract<StreamEvent, { type: 'start' }>;
export type TextStartEvent = Extract<StreamEvent, { type: 'text-start' }>;
export type TextDeltaEvent = Extract<StreamEvent, { type: 'text-delta' }>;
export type TextEndEvent = Extract<StreamEvent, { type: 'text-end' }>;
export type ToolInputStartEvent = Extract<StreamEvent, { type: 'tool-input-start' }>;
export type ToolInputDeltaEvent = Extract<StreamEvent, { type: 'tool-input-delta' }>;
export type ToolInputAvailableEvent = Extract<StreamEvent, { type: 'tool-input-available' }>;
export type ToolOutputAvailableEvent = Extract<StreamEvent, { type: 'tool-output-available' }>;
export type ToolCallEndEvent = Extract<StreamEvent, { type: 'tool-call-end' }>;
export type FinishEvent = Extract<StreamEvent, { type: 'finish' }>;
export type ErrorEvent = Extract<StreamEvent, { type: 'error' }>;

/**
 * API Response types
 */
export interface CreateConversationResponse {
  ok: boolean;
  conversationId: string;
}

export interface SendMessageResponse {
  ok: boolean;
  messageId: string;
}

/**
 * Configuration options for stream
 */
export interface StreamOptions {
  /** Base URL for API requests (defaults to relative paths) */
  baseUrl?: string;
  /** Automatically reconnect on disconnect (default: true) */
  autoReconnect?: boolean;
  /** Delay in ms before reconnecting (default: 1000) */
  reconnectDelay?: number;
  /**
   * Callback for stream errors
   * @default Logs to console.error
   * @remarks In production, provide your own error handler to properly handle errors
   */
  onError?: (error: Error) => void;
}

/**
 * Accumulated message state
 */
export interface MessageState {
  id: string;
  content: string;
  isComplete: boolean;
  role: 'user' | 'assistant';
  toolCalls?: ToolCallState[];
}

/**
 * Tool call state
 */
export interface ToolCallState {
  toolCallId: string;
  toolName: string;
  input?: unknown;
  output?: unknown;
  isComplete: boolean;
}

/**
 * Event handler types
 */
export type StreamEventHandler = (event: StreamEvent) => void;
export type TextDeltaHandler = (event: TextDeltaEvent) => void;
export type FinishHandler = (event: FinishEvent) => void;
export type ErrorHandler = (event: ErrorEvent) => void;

# Agent Chat SDK

Simple SDK for building AI Agent Chat interfaces in Taskade Genesis apps.

**Key Features:**
- Manual conversation creation (consumer must create conversation before use)
- Stream opens when conversationId is provided
- Stream stays open throughout (handles reconnection automatically)
- Supports creating/switching conversations

## Quick Start

```typescript
import { useAgentChat, createConversation } from '@/lib/agent-chat';
import { useState } from 'react';

function ChatComponent() {
  const [conversationId, setConversationId] = useState<string | null>(null);
  const { sendMessage, messages, isConnected } = useAgentChat(agentId, conversationId);

  // Create conversation manually
  const handleStartChat = async () => {
    const { conversationId: newId } = await createConversation(agentId);
    setConversationId(newId);
  };

  return (
    <div>
      {!conversationId && <button onClick={handleStartChat}>Start Chat</button>}
      {messages.map(msg => (
        <div key={msg.id}>
          {msg.role === 'user' ? 'You: ' : 'Agent: '}
          {msg.content}
          {msg.toolCalls && msg.toolCalls.length > 0 && (
            <div>Tool calls: {msg.toolCalls.length}</div>
          )}
        </div>
      ))}
      <button onClick={() => sendMessage('Hello!')}>Send</button>
    </div>
  );
}
```

## Multiple Conversations

```typescript
const [conversationId, setConversationId] = useState<string | null>(null);
const {
  sendMessage,
  messages,
  createConversation: createNewConversation,    // Create new conversation
  switchConversation,    // Switch to existing conversation
} = useAgentChat(agentId, conversationId);

// Create new chat
const handleNewChat = async () => {
  const newConvoId = await createNewConversation();
  setConversationId(newConvoId);
};

// Switch to different conversation
const handleSwitchChat = (existingConvoId: string) => {
  switchConversation(existingConvoId);
  setConversationId(existingConvoId);
};
```

## API Reference

**`useAgentChat(agentId, conversationId)`**
- `agentId` - The agent ID (required)
- `conversationId` - The conversation ID (required, pass `null` if not yet created)
- `sendMessage(text)` - Send message to current conversation (requires conversationId)
- `messages` - Array of messages (MessageState[])
- `isConnected` - Stream connection status
- `conversationId` - Current conversation ID (from hook return)
- `createConversation()` - Create new conversation (returns ID)
- `switchConversation(id)` - Switch to different conversation
- `error` - Current error, if any

**Note:** The hook will only connect the stream when `conversationId` is provided (not `null`). You must create a conversation manually before the stream can connect.

**Advanced (low-level):**
- `createConversation(agentId)` - Direct API call
- `sendMessage(agentId, conversationId, text)` - Direct API call
- `AgentChatStream` - Stream manager class

See `index.ts` for full type exports.

## Requirements

- Agent must have **public visibility** enabled before creating conversation
- Stream stays open permanently (never close after first response)
- Text deltas are automatically accumulated (append, never replace)

import type { CreateConversationResponse, SendMessageResponse } from './types';

/**
 * Configuration for API client
 */
export interface ClientOptions {
  /** Base URL for API requests (defaults to relative paths) */
  baseUrl?: string;
}

/**
 * Checks if a string is null, undefined, or empty after trimming
 */
function isEmptyString(value: string | null | undefined): boolean {
  return value == null || value.trim().length === 0;
}

/**
 * Creates a new public agent conversation
 *
 * @param agentId - The agent ID
 * @param options - Optional client configuration
 * @returns Promise resolving to conversation ID
 * @throws Error if conversation creation fails
 *
 * @example
 * ```typescript
 * const { conversationId } = await createConversation('agent-456');
 * ```
 */
export async function createConversation(
  agentId: string,
  options?: ClientOptions,
): Promise<CreateConversationResponse> {
  if (isEmptyString(agentId)) {
    throw new Error('Agent ID cannot be empty');
  }

  const baseUrl = options?.baseUrl ?? '';
  const url = `${baseUrl}/api/taskade/agents/${encodeURIComponent(agentId)}/public-conversations`;

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
  });

  // Read response body once
  const contentType = response.headers.get('content-type') || '';
  const responseText = await response.text().catch(() => '');

  if (!response.ok) {
    throw new Error(
      `Failed to create conversation: ${response.status} ${responseText || 'Unknown error'}`,
    );
  }

  if (!contentType.includes('application/json')) {
    throw new Error(
      `Invalid response format: expected JSON, got ${contentType}. Response: ${responseText.substring(
        0,
        100,
      )}`,
    );
  }

  try {
    const data = JSON.parse(responseText);
    return data as CreateConversationResponse;
  } catch (err) {
    throw new Error(
      `Failed to parse JSON response: ${
        err instanceof Error ? err.message : 'Unknown error'
      }. Response: ${responseText.substring(0, 200)}`,
    );
  }
}

/**
 * Sends a message to an existing conversation
 *
 * @param agentId - The agent ID
 * @param conversationId - The conversation ID
 * @param text - The message text to send
 * @param options - Optional client configuration
 * @returns Promise resolving when message is sent
 * @throws Error if message sending fails (e.g., conversation not idle, conversation ended)
 *
 * @example
 * ```typescript
 * await sendMessage('agent-456', 'convo-789', 'Hello!');
 * ```
 */
export async function sendMessage(
  agentId: string,
  conversationId: string,
  text: string,
  options?: ClientOptions,
): Promise<SendMessageResponse> {
  if (isEmptyString(agentId)) {
    throw new Error('Agent ID cannot be empty');
  }

  if (isEmptyString(conversationId)) {
    throw new Error('Conversation ID cannot be empty');
  }

  const trimmedText = text.trim();
  if (isEmptyString(trimmedText)) {
    throw new Error('Message text cannot be empty');
  }

  const baseUrl = options?.baseUrl ?? '';
  const url = `${baseUrl}/api/taskade/agents/${encodeURIComponent(
    agentId,
  )}/public-conversations/${encodeURIComponent(conversationId)}/messages`;

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ text: trimmedText }),
  });

  // Read response body once
  const contentType = response.headers.get('content-type') || '';
  const responseText = await response.text().catch(() => '');

  if (!response.ok) {
    // Parse error message if available
    let errorMessage = `Failed to send message: ${response.status}`;
    try {
      const errorData = JSON.parse(responseText);
      if (errorData.message) {
        errorMessage = errorData.message;
      }
    } catch {
      // Use default error message with response text
      if (responseText) {
        errorMessage = `${errorMessage}: ${responseText.substring(0, 100)}`;
      }
    }
    throw new Error(errorMessage);
  }

  if (!contentType.includes('application/json')) {
    throw new Error(
      `Invalid response format: expected JSON, got ${contentType}. Response: ${responseText.substring(
        0,
        100,
      )}`,
    );
  }

  try {
    const data = JSON.parse(responseText);
    return data as SendMessageResponse;
  } catch (err) {
    throw new Error(
      `Failed to parse JSON response: ${
        err instanceof Error ? err.message : 'Unknown error'
      }. Response: ${responseText.substring(0, 200)}`,
    );
  }
}

import type {
  ErrorEvent,
  FinishEvent,
  MessageState,
  StreamEvent,
  StreamEventHandler,
  StreamOptions,
  TextDeltaEvent,
} from './types';
import { StreamEventSchema } from './types';

/**
 * Event emitter interface for stream events
 */
type EventMap = {
  event: StreamEventHandler;
  'text-delta': (event: TextDeltaEvent) => void;
  finish: (event: FinishEvent) => void;
  error: (event: ErrorEvent) => void;
  open: () => void;
  close: () => void;
};

/**
 * Manages SSE connection for agent conversation streaming
 *
 * Handles connection lifecycle, event parsing, and message state accumulation.
 * The stream stays open permanently and handles all messages in the conversation.
 *
 * **Memory Management**: The `messageStates` Map accumulates messages throughout the conversation.
 * For long-running conversations, call `clearMessages()` when switching conversations
 * or create a new stream instance for new conversations.
 *
 * @example
 * ```typescript
 * const stream = new AgentChatStream('agent-456', 'convo-789');
 * stream.on('text-delta', ({ id, delta }) => {
 *   // Append delta to message content
 * });
 * stream.connect();
 * ```
 */
export class AgentChatStream {
  private agentId: string;
  private conversationId: string;
  private options: Required<StreamOptions>;
  private eventSource: EventSource | null = null;
  private listeners: Map<keyof EventMap, Set<EventMap[keyof EventMap]>> = new Map();
  private reconnectTimeout: ReturnType<typeof setTimeout> | null = null;
  private messageStates: Map<string, MessageState> = new Map();
  private currentMessageId: string | null = null;
  private isConnecting = false;

  constructor(agentId: string, conversationId: string, options?: StreamOptions) {
    this.agentId = agentId;
    this.conversationId = conversationId;
    this.options = {
      baseUrl: options?.baseUrl ?? '',
      autoReconnect: options?.autoReconnect ?? true,
      reconnectDelay: options?.reconnectDelay ?? 1000,
      onError:
        options?.onError ??
        ((error: Error) => {
          // Log errors by default to help with debugging
          // In production, consumers should provide their own error handler
          console.error('[AgentChatStream] Unhandled error:', error);
        }),
    };
  }

  /**
   * Clear all accumulated message states
   * Useful when switching conversations or resetting the stream state
   */
  clearMessages(): void {
    this.messageStates.clear();
    this.currentMessageId = null;
  }

  /**
   * Update the conversation ID for this stream
   * Useful when switching to a new conversation while keeping stream open
   * Automatically clears message states when switching conversations
   */
  setConversationId(conversationId: string): void {
    if (this.conversationId === conversationId) {
      return;
    }
    // Track both connected and connecting states to handle race conditions
    const wasConnected = this.isConnected;
    const wasConnecting = this.isConnecting;
    this.disconnect();
    this.conversationId = conversationId;
    // Clear message state when switching conversations
    this.clearMessages();
    // Reconnect if we were connected or in the process of connecting
    if (wasConnected || wasConnecting) {
      this.connect();
    }
  }

  /**
   * Opens SSE connection to stream endpoint
   * Stream stays open permanently - never close after first response
   */
  connect(): void {
    // Check isConnecting first since it's set synchronously before any async work
    // This prevents race conditions where connect() is called multiple times
    // before eventSource is assigned
    if (this.isConnecting) {
      return; // Already connecting
    }

    if (this.eventSource?.readyState === EventSource.OPEN) {
      return; // Already connected
    }

    this.isConnecting = true;
    this.disconnect(); // Clean up any existing connection

    const baseUrl = this.options.baseUrl;
    const url = `${baseUrl}/api/taskade/agents/${encodeURIComponent(
      this.agentId,
    )}/public-conversations/${encodeURIComponent(this.conversationId)}/stream`;

    // Validate required parameters
    if (!this.agentId || !this.conversationId) {
      const error = new Error(
        `Missing required parameters: agentId=${this.agentId || 'null'}, conversationId=${
          this.conversationId || 'null'
        }`,
      );
      this.options.onError(error);
      this.emit('error', {
        type: 'error',
        errorText: error.message,
      });
      this.isConnecting = false;
      return;
    }

    try {
      this.eventSource = new EventSource(url);

      this.eventSource.onopen = () => {
        this.isConnecting = false;
        this.emit('open');
      };

      this.eventSource.onmessage = (e) => {
        try {
          const data = JSON.parse(e.data);
          const event = StreamEventSchema.parse(data);
          this.handleEvent(event);
        } catch (error) {
          const parseError = error instanceof Error ? error : new Error('Failed to parse event');
          this.options.onError(parseError);
          this.emit('error', {
            type: 'error',
            errorText: `Parse error: ${parseError.message}`,
          });
        }
      };

      this.eventSource.onerror = () => {
        this.isConnecting = false;

        // EventSource doesn't provide detailed error info, but we can check readyState
        if (this.eventSource?.readyState === EventSource.CLOSED) {
          this.emit('close');

          // Auto-reconnect if enabled
          if (this.options.autoReconnect) {
            this.scheduleReconnect();
          }
        } else if (this.eventSource?.readyState === EventSource.CONNECTING) {
          // Still connecting, might be a temporary issue
          // Don't emit error yet, wait for connection to complete or fail
        } else {
          // Connection error
          const error = new Error('EventSource connection error');
          this.options.onError(error);
          this.emit('error', {
            type: 'error',
            errorText: 'Stream connection error',
          });
        }
      };
    } catch (error) {
      // EventSource constructor threw an error (e.g., invalid URL)
      this.isConnecting = false;
      const constructorError =
        error instanceof Error ? error : new Error('Failed to create EventSource');
      this.options.onError(constructorError);
      this.emit('error', {
        type: 'error',
        errorText: `Failed to create connection: ${constructorError.message}`,
      });
    }
  }

  /**
   * Closes SSE connection
   */
  disconnect(): void {
    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout);
      this.reconnectTimeout = null;
    }

    if (this.eventSource) {
      this.eventSource.close();
      this.eventSource = null;
    }

    this.isConnecting = false;
  }

  /**
   * Subscribe to stream events
   *
   * @param event - Event type to listen for
   * @param handler - Callback function
   * @returns Unsubscribe function
   */
  on<K extends keyof EventMap>(event: K, handler: EventMap[K]): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(handler);

    // Return unsubscribe function
    return () => {
      this.listeners.get(event)?.delete(handler);
    };
  }

  /**
   * Unsubscribe from stream events
   */
  off<K extends keyof EventMap>(event: K, handler: EventMap[K]): void {
    this.listeners.get(event)?.delete(handler);
  }

  /**
   * Get current connection state
   */
  get isConnected(): boolean {
    // Check readyState directly - more reliable across browsers
    return this.eventSource?.readyState === EventSource.OPEN;
  }

  /**
   * Get accumulated message states
   */
  get messages(): Map<string, MessageState> {
    return new Map(this.messageStates);
  }

  /**
   * Get message state by ID
   */
  getMessage(id: string): MessageState | undefined {
    return this.messageStates.get(id);
  }

  /**
   * Handle incoming SSE event
   */
  private handleEvent(event: StreamEvent): void {
    // Emit generic event
    this.emit('event', event);

    switch (event.type) {
      case 'start':
        this.currentMessageId = event.messageId;
        // Always create/update message on start to ensure it exists
        if (!this.messageStates.has(event.messageId)) {
          this.messageStates.set(event.messageId, {
            id: event.messageId,
            content: '',
            isComplete: false,
            role: 'assistant',
          });
        }
        break;

      case 'text-start':
        // event.id is a text segment ID, but text belongs to the current message (from 'start' event)
        // Ensure the current message exists
        if (this.currentMessageId) {
          if (!this.messageStates.has(this.currentMessageId)) {
            this.messageStates.set(this.currentMessageId, {
              id: this.currentMessageId,
              content: '',
              isComplete: false,
              role: 'assistant',
            });
          }
        }
        break;

      case 'text-delta': {
        // event.id is a text segment ID, but text belongs to the current message (from 'start' event)
        // Append delta to the current message's content
        if (this.currentMessageId) {
          const existingState = this.messageStates.get(this.currentMessageId);
          if (existingState) {
            // Create new object with updated content to ensure change detection
            const updatedState: MessageState = {
              ...existingState,
              content: existingState.content + event.delta,
            };
            this.messageStates.set(this.currentMessageId, updatedState);
          } else {
            // Create message if it doesn't exist (shouldn't happen, but handle gracefully)
            this.messageStates.set(this.currentMessageId, {
              id: this.currentMessageId,
              content: event.delta,
              isComplete: false,
              role: 'assistant',
            });
          }
        }
        this.emit('text-delta', event);
        break;
      }

      case 'text-end': {
        // event.id is a text segment ID, but text belongs to the current message (from 'start' event)
        // Text part is complete, but don't mark entire message as complete (message completes on 'finish' event)
        break;
      }

      case 'tool-input-start': {
        // Use messageId from event if available (for child segments), otherwise fall back to currentMessageId
        const messageId =
          'messageId' in event && event.messageId ? event.messageId : this.currentMessageId;
        const toolMessage = messageId ? this.messageStates.get(messageId) : undefined;
        if (toolMessage) {
          const updatedState: MessageState = {
            ...toolMessage,
            toolCalls: [
              ...(toolMessage.toolCalls ?? []),
              {
                toolCallId: event.toolCallId,
                toolName: event.toolName,
                isComplete: false,
              },
            ],
          };
          this.messageStates.set(toolMessage.id, updatedState);
        }
        break;
      }

      case 'tool-input-delta': {
        // Use messageId from event if available (for child segments), otherwise fall back to currentMessageId
        const messageId =
          'messageId' in event && event.messageId ? event.messageId : this.currentMessageId;
        const toolMessage = messageId ? this.messageStates.get(messageId) : undefined;
        if (toolMessage?.toolCalls) {
          const toolCallIndex = toolMessage.toolCalls.findIndex(
            (tc) => tc.toolCallId === event.toolCallId,
          );
          if (toolCallIndex !== -1) {
            const existingToolCall = toolMessage.toolCalls[toolCallIndex];
            // Accumulate inputTextDelta into input (stored as string during streaming)
            // When tool-input-available arrives, it will replace this with the parsed object
            const currentInput =
              typeof existingToolCall.input === 'string' ? existingToolCall.input : '';
            const updatedState: MessageState = {
              ...toolMessage,
              toolCalls: toolMessage.toolCalls.map((tc, index) =>
                index === toolCallIndex
                  ? { ...tc, input: currentInput + event.inputTextDelta }
                  : tc,
              ),
            };
            this.messageStates.set(toolMessage.id, updatedState);
          }
        }
        break;
      }

      case 'tool-input-available': {
        // Use messageId from event if available (for child segments), otherwise fall back to currentMessageId
        const messageId =
          'messageId' in event && event.messageId ? event.messageId : this.currentMessageId;
        const toolMessage = messageId ? this.messageStates.get(messageId) : undefined;
        if (toolMessage?.toolCalls) {
          const toolCallIndex = toolMessage.toolCalls.findIndex(
            (tc) => tc.toolCallId === event.toolCallId,
          );
          if (toolCallIndex !== -1) {
            const updatedState: MessageState = {
              ...toolMessage,
              toolCalls: toolMessage.toolCalls.map((tc, index) =>
                index === toolCallIndex ? { ...tc, input: event.input } : tc,
              ),
            };
            this.messageStates.set(toolMessage.id, updatedState);
          }
        }
        break;
      }

      case 'tool-output-available': {
        // Use messageId from event if available (for child segments), otherwise fall back to currentMessageId
        const messageId =
          'messageId' in event && event.messageId ? event.messageId : this.currentMessageId;
        const toolMessage = messageId ? this.messageStates.get(messageId) : undefined;
        if (toolMessage?.toolCalls) {
          const toolCallIndex = toolMessage.toolCalls.findIndex(
            (tc) => tc.toolCallId === event.toolCallId,
          );
          if (toolCallIndex !== -1) {
            const updatedState: MessageState = {
              ...toolMessage,
              toolCalls: toolMessage.toolCalls.map((tc, index) =>
                index === toolCallIndex ? { ...tc, output: event.output } : tc,
              ),
            };
            this.messageStates.set(toolMessage.id, updatedState);
          }
        }
        break;
      }

      case 'tool-call-end': {
        // Use messageId from event if available (for child segments), otherwise fall back to currentMessageId
        const messageId =
          'messageId' in event && event.messageId ? event.messageId : this.currentMessageId;
        const toolMessage = messageId ? this.messageStates.get(messageId) : undefined;
        if (toolMessage?.toolCalls) {
          const toolCallIndex = toolMessage.toolCalls.findIndex(
            (tc) => tc.toolCallId === event.toolCallId,
          );
          if (toolCallIndex !== -1) {
            const updatedState: MessageState = {
              ...toolMessage,
              toolCalls: toolMessage.toolCalls.map((tc, index) =>
                index === toolCallIndex ? { ...tc, isComplete: true } : tc,
              ),
            };
            this.messageStates.set(toolMessage.id, updatedState);
          }
        }
        break;
      }

      case 'finish':
        if (this.currentMessageId) {
          const finishedMessage = this.messageStates.get(this.currentMessageId);
          if (finishedMessage) {
            const updatedState: MessageState = {
              ...finishedMessage,
              isComplete: true,
            };
            this.messageStates.set(this.currentMessageId, updatedState);
          }
        }
        this.emit('finish', event);
        break;

      case 'error':
        this.emit('error', event);
        this.options.onError(new Error(event.errorText));
        break;
    }
  }

  /**
   * Emit event to all listeners
   */
  private emit<K extends keyof EventMap>(event: K, ...args: Parameters<EventMap[K]>): void {
    const handlers = this.listeners.get(event);
    if (handlers) {
      handlers.forEach((handler) => {
        try {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (handler as (...args: any[]) => void)(...args);
        } catch (error) {
          this.options.onError(error instanceof Error ? error : new Error('Handler error'));
        }
      });
    }
  }

  /**
   * Schedule reconnection attempt
   */
  private scheduleReconnect(): void {
    if (this.reconnectTimeout) {
      return; // Already scheduled
    }

    this.reconnectTimeout = setTimeout(() => {
      this.reconnectTimeout = null;
      if (this.options.autoReconnect) {
        this.connect();
      }
    }, this.options.reconnectDelay);
  }
}

import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

