/* Full screen spinner styles */
.genesis__spinner-container {
  position: fixed;
  inset: 0;
  background: #000000;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}

.genesis__spinner-ring {
  width: 20px;
  height: 20px;
  border: 1.5px solid transparent;
  border-top: 1.5px solid rgba(255, 255, 255, 0.6);
  border-radius: 50%;
  animation: genesis__spin 1s linear infinite;
}

@keyframes genesis__spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* Respect reduced motion preferences */
@media (prefers-reduced-motion: reduce) {
  .genesis__spinner-ring {
    animation: none;
    border-top-color: rgba(255, 255, 255, 0.9);
  }
}

/* Gentle floating particle animation */
@keyframes float-up {
  0% {
    transform: translateY(0) translateX(0) scale(1);
    opacity: 0;
  }
  10% {
    opacity: var(--particle-opacity, 0.1);
  }
  90% {
    opacity: var(--particle-opacity, 0.1);
  }
  100% {
    transform: translateY(-100vh) translateX(30px) scale(0.5);
    opacity: 0;
  }
}

.animate-float-up {
  animation: float-up linear infinite;
  will-change: transform, opacity;
}

/* Disable particles on reduced motion */
@media (prefers-reduced-motion: reduce) {
  .animate-float-up {
    animation: none;
    opacity: 0;
  }
}

