      {/* Google Drive Tip */}
      <div
        className={cn(
          'p-4 rounded-xl',
          'bg-gradient-to-r from-blue-500/10 via-cyan-500/10 to-blue-500/10',
          'border border-primary/20',
          'backdrop-blur-sm'
