              Any files uploaded to your connected Drive folder will instantly appear here. 
              Perfect for seamless file sharing with your team!
            </p>
            <a
              href="https://www.taskade.com/automation"
              target="_blank"
              rel="noopener noreferrer"
              className={cn(
                'inline-flex items-center gap-1.5 mt-3',
                'text-sm font-medium text-primary',
                'hover:text-primary/80 transition-colors',
                'group'
              )}
            >
              Learn about Taskade Automations
              <ExternalLink className="w-3.5 h-3.5 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
            </a>
          </div>
        </div>
      </div>

      {/* Files List */}
      <div className="space-y-2">
        {filteredFiles.map((file, index) => {
          const fileName = file.fieldValues['/attributes/@file4'] || file.fieldValues['/text'];
          const fileType = file.fieldValues['/attributes/@ftyp6'];
          const project = file.fieldValues['/attributes/@proj5'];
          const uploadDate = file.fieldValues['/attributes/@upld8'];
          const uploadedBy = file.fieldValues['/attributes/@upby9'];
          const version = file.fieldValues['/attributes/@vers0'];
