          </p>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mail, Bell, AlertTriangle, Check, Plus, X, Send } from 'lucide-react';
import { communicationsApi } from '../lib/api';
import type { Communication } from '../types';
import { cn } from '../lib/utils';
import axios from 'axios';

export function Messages() {
  const [messages, setMessages] = useState<Communication[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<string>('all');
  const [isComposeOpen, setIsComposeOpen] = useState(false);
  const [composing, setComposing] = useState(false);
  const [formData, setFormData] = useState({
    type: 'opt-msg',
    subject: '',
    message: '',
    from: '',
    client: ''
  });

  useEffect(() => {
    const fetchMessages = async () => {
      try {
        const data = await communicationsApi.getAll();
        setMessages(data);
      } catch (error) {
        console.error('Error fetching messages:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchMessages();
  }, []);

  const handleMarkAsRead = async (id: string) => {
    try {
      await communicationsApi.markAsRead(id);
      setMessages(messages.map(m => 
        m.id === id 
          ? { ...m, fieldValues: { ...m.fieldValues, '/attributes/@read3': 'opt-read' } }
          : m
      ));
    } catch (error) {
      console.error('Error marking message as read:', error);
    }
  };

  const handleComposeMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    setComposing(true);

    try {
      await axios.post('/api/taskade/projects/Xpy6gkXdWBbZnpAT/nodes', {
        '/attributes/@type2': formData.type,
        '/attributes/@read3': 'opt-unread',
        '/attributes/@subj0': formData.subject,
        '/attributes/@msg11': formData.message,
        '/attributes/@from8': formData.from,
        '/attributes/@clie9': formData.client,
        '/text': formData.subject
      });

      // Refresh messages
      const data = await communicationsApi.getAll();
      setMessages(data);

      // Reset form and close dialog
      setFormData({
        type: 'opt-msg',
        subject: '',
        message: '',
        from: '',
        client: ''
      });
      setIsComposeOpen(false);
    } catch (error) {
      console.error('Error creating message:', error);
    } finally {
      setComposing(false);
    }
  };

  const filteredMessages = filter === 'all'
    ? messages
    : filter === 'unread'
    ? messages.filter(m => m.fieldValues['/attributes/@read3'] === 'opt-unread')
    : messages.filter(m => m.fieldValues['/attributes/@type2'] === filter);

  const filters = [
    { value: 'all', label: 'All', count: messages.length },
    { value: 'unread', label: 'Unread', count: messages.filter(m => m.fieldValues['/attributes/@read3'] === 'opt-unread').length },
    { value: 'opt-msg', label: 'Messages', count: messages.filter(m => m.fieldValues['/attributes/@type2'] === 'opt-msg').length },
    { value: 'opt-notif', label: 'Notifications', count: messages.filter(m => m.fieldValues['/attributes/@type2'] === 'opt-notif').length },
  ];

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'opt-msg': return Mail;
      case 'opt-notif': return Bell;
      case 'opt-alert': return AlertTriangle;
      default: return Mail;
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'opt-msg': return 'from-blue-500 to-cyan-500';
      case 'opt-notif': return 'from-purple-500 to-pink-500';
      case 'opt-alert': return 'from-red-500 to-orange-500';
      default: return 'from-slate-500 to-gray-500';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-8 relative">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-foreground tracking-tight">Messages</h1>
          <p className="text-muted-foreground mt-2">Stay updated with project communications</p>
        </div>
        <button
          onClick={() => setIsComposeOpen(true)}
          className={cn(
            'px-4 py-2.5 rounded-xl',
            'bg-amber-600 text-white',
            'shadow-lg shadow-amber-600/25',
            'font-medium text-sm',
            'flex items-center gap-2',
            'transition-all duration-300',
            'hover:scale-105 active:scale-95'
          )}
        >
          <Plus className="w-4 h-4" />
          Compose
        </button>
      </div>

      {/* Filters */}
      <div className="flex items-center gap-2 overflow-x-auto pb-2">
        {filters.map((f) => {
          const isActive = filter === f.value;
          return (
            <button
              key={f.value}
              onClick={() => setFilter(f.value)}
              className={cn(
                'px-4 py-2.5 rounded-xl whitespace-nowrap font-medium text-sm',
                'transition-all duration-300',
                isActive
                  ? 'bg-amber-600 text-white shadow-lg shadow-amber-600/25'
                  : 'bg-card/50 text-muted-foreground hover:bg-card hover:text-foreground border border-border/50'
              )}
            >
              {f.label} <span className="ml-1 opacity-60">({f.count})</span>
            </button>
          );
        })}
      </div>

      {/* Messages List */}
      <div className="space-y-3">
        {filteredMessages.map((message, index) => {
          const isUnread = message.fieldValues['/attributes/@read3'] === 'opt-unread';
          const type = message.fieldValues['/attributes/@type2'];
          const Icon = getTypeIcon(type);
          const iconColor = getTypeColor(type);

          return (
            <div
              key={message.id}
              className={cn(
                'p-5 rounded-xl',
                'bg-card/50 backdrop-blur-sm border border-border/50',
                'hover:bg-card hover:border-border hover:shadow-lg hover:shadow-primary/5',
                'transition-all duration-300',
                isUnread && 'border-primary/30 bg-primary/5'
              )}
            >
              <div className="flex items-start gap-4">
                {/* Icon */}
                <div className={cn(
                  'w-10 h-10 rounded-xl flex-shrink-0',
                  'bg-gradient-to-br', iconColor,
                  'bg-opacity-10 border border-border',
                  'flex items-center justify-center'
                )}>
                  <Icon className="w-5 h-5 text-primary" />
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-4 mb-2">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        {isUnread && (
                          <div className="w-2 h-2 bg-primary rounded-full flex-shrink-0" />
                        )}
                        <h3 className="font-medium text-foreground">
                          {message.fieldValues['/attributes/@subj0']}
                        </h3>
                      </div>
                      <p className="text-sm text-muted-foreground mt-1">
                        From: {message.fieldValues['/attributes/@from8']}
                      </p>
                    </div>
                    {isUnread && (
                      <button
                        onClick={() => handleMarkAsRead(message.id)}
                        className={cn(
                          'px-3 py-1.5 rounded-lg',
                          'bg-card border border-border',
                          'text-xs text-muted-foreground',
                          'hover:bg-accent hover:text-foreground',
                          'transition-all duration-200',
                          'flex items-center gap-1.5'
                        )}
                      >
                        <Check className="w-3 h-3" />
                        Mark Read
                      </button>
                    )}
                  </div>

                  <p className="text-foreground text-sm leading-relaxed">
                    {message.fieldValues['/attributes/@msg11']}
                  </p>

                  {message.fieldValues['/attributes/@clie9'] && (
                    <p className="text-xs text-muted-foreground mt-3">
                      Client: {message.fieldValues['/attributes/@clie9']}
                    </p>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {filteredMessages.length === 0 && (
        <div className="text-center py-20">
          <div className="w-16 h-16 rounded-2xl bg-muted/50 flex items-center justify-center mx-auto mb-4">
            <Mail className="w-8 h-8 text-muted-foreground" />
          </div>
          <p className="text-muted-foreground text-lg">No messages found</p>
        </div>
