                {/* Header */}
                <div className="flex items-center justify-between mb-6">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
                      <Mail className="w-5 h-5 text-white" />
                    </div>
                    <div>
                      <h2 className="text-xl font-bold text-foreground">Compose Message</h2>
                      <p className="text-sm text-muted-foreground">Send a new message</p>
                    </div>
                  </div>
                  <button
                    onClick={() => setIsComposeOpen(false)}
                    className="p-2 rounded-lg hover:bg-accent transition-colors"
                  >
                    <X className="w-5 h-5 text-muted-foreground" />
                  </button>
                </div>

                {/* Form */}
                <form onSubmit={handleComposeMessage} className="space-y-4">
                  {/* Type */}
                  <div>
                    <label className="text-sm font-medium text-foreground mb-2 block">
                      Type
                    </label>
                    <select
                      value={formData.type}
                      onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                      className={cn(
                        'w-full px-4 py-2.5 rounded-xl',
                        'bg-background border border-border',
                        'text-foreground',
                        'focus:outline-none focus:ring-2 focus:ring-primary/50',
                        'transition-all duration-200'
                      )}
                      required
                    >
                      <option value="opt-msg">Message</option>
                      <option value="opt-notif">Notification</option>
                      <option value="opt-alert">Alert</option>
                    </select>
                  </div>

                  {/* From */}
                  <div>
                    <label className="text-sm font-medium text-foreground mb-2 block">
                      From
                    </label>
                    <input
                      type="text"
                      value={formData.from}
                      onChange={(e) => setFormData({ ...formData, from: e.target.value })}
                      placeholder="Your name or email"
                      className={cn(
                        'w-full px-4 py-2.5 rounded-xl',
                        'bg-background border border-border',
                        'text-foreground placeholder:text-muted-foreground',
                        'focus:outline-none focus:ring-2 focus:ring-primary/50',
                        'transition-all duration-200'
                      )}
                      required
                    />
                  </div>

                  {/* Client (Optional) */}
                  <div>
                    <label className="text-sm font-medium text-foreground mb-2 block">
                      Client <span className="text-muted-foreground">(Optional)</span>
                    </label>
                    <input
                      type="text"
                      value={formData.client}
                      onChange={(e) => setFormData({ ...formData, client: e.target.value })}
                      placeholder="Client name"
                      className={cn(
                        'w-full px-4 py-2.5 rounded-xl',
                        'bg-background border border-border',
                        'text-foreground placeholder:text-muted-foreground',
                        'focus:outline-none focus:ring-2 focus:ring-primary/50',
                        'transition-all duration-200'
                      )}
                    />
                  </div>

                  {/* Subject */}
                  <div>
                    <label className="text-sm font-medium text-foreground mb-2 block">
                      Subject
                    </label>
                    <input
                      type="text"
                      value={formData.subject}
                      onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                      placeholder="Message subject"
                      className={cn(
                        'w-full px-4 py-2.5 rounded-xl',
                        'bg-background border border-border',
                        'text-foreground placeholder:text-muted-foreground',
                        'focus:outline-none focus:ring-2 focus:ring-primary/50',
                        'transition-all duration-200'
                      )}
                      required
                    />
                  </div>

                  {/* Message */}
                  <div>
                    <label className="text-sm font-medium text-foreground mb-2 block">
                      Message
                    </label>
                    <textarea
                      value={formData.message}
                      onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                      placeholder="Write your message here..."
                      rows={6}
                      className={cn(
                        'w-full px-4 py-2.5 rounded-xl',
                        'bg-background border border-border',
                        'text-foreground placeholder:text-muted-foreground',
                        'focus:outline-none focus:ring-2 focus:ring-primary/50',
                        'transition-all duration-200',
                        'resize-none'
                      )}
                      required
                    />
                  </div>

                  {/* Actions */}
                  <div className="flex items-center gap-3 pt-2">
                    <button
                      type="button"
                      onClick={() => setIsComposeOpen(false)}
                      className={cn(
                        'flex-1 px-4 py-2.5 rounded-xl',
                        'bg-card border border-border',
                        'text-muted-foreground',
                        'hover:bg-accent hover:text-foreground',
                        'transition-all duration-200',
                        'font-medium text-sm'
                      )}
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      disabled={composing}
                      className={cn(
                        'flex-1 px-4 py-2.5 rounded-xl',
                        'bg-gradient-to-br from-blue-500 to-purple-600 text-white',
                        'shadow-lg shadow-primary/25',
                        'font-medium text-sm',
                        'flex items-center justify-center gap-2',
                        'transition-all duration-300',
                        'disabled:opacity-50 disabled:cursor-not-allowed'
                      )}
                    >
                      {composing ? (
                        <>
                          <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                          Sending...
                        </>
                      ) : (
                        <>
                          <Send className="w-4 h-4" />
                          Send Message
                        </>
                      )}
                    </button>
                  </div>
                </form>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Filter, Calendar, DollarSign, TrendingUp, Folder } from 'lucide-react';
import { projectsApi } from '../lib/api';
import type { Project } from '../types';
import { statusColors, statusLabels, priorityLabels, priorityColors } from '../types';
import { cn } from '../lib/utils';
import { format, parseISO } from 'date-fns';

export function Projects() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<string>('all');
  const [priorityFilter, setPriorityFilter] = useState<string>('all');

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const data = await projectsApi.getAll();
        setProjects(data);
      } catch (error) {
        console.error('Error fetching projects:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchProjects();
  }, []);

  const filteredProjects = projects.filter(p => {
    const statusMatch = filter === 'all' || p.fieldValues['/attributes/@stat3'] === filter;
    const priorityMatch = priorityFilter === 'all' || p.fieldValues['/attributes/@prio7'] === priorityFilter;
    return statusMatch && priorityMatch;
  });

  const filters = [
