            { value: 'opt-med', label: 'Medium', count: projects.filter(p => p.fieldValues['/attributes/@prio7'] === 'opt-med').length },
            { value: 'opt-low', label: 'Low', count: projects.filter(p => p.fieldValues['/attributes/@prio7'] === 'opt-low').length },
