import { useEffect, useState, useMemo } from 'react';
import { motion } from 'framer-motion';
import { FolderOpen, BarChart3, Mail, CheckCircle2, Folder } from 'lucide-react';
import { projectsApi, communicationsApi } from '../lib/api';
import type { Project, Communication } from '../types';
import { statusColors, statusLabels } from '../types';
import { cn } from '../lib/utils';
import { format, parseISO } from 'date-fns';

// Progress bar colors for visual variety
const progressColors = [
  'bg-blue-600',
  'bg-purple-600',
  'bg-emerald-600',
  'bg-amber-600',
  'bg-rose-600',
  'bg-cyan-600',
  'bg-indigo-600',
  'bg-pink-600',
];

export function Dashboard() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [communications, setCommunications] = useState<Communication[]>([]);
  const [loading, setLoading] = useState(true);

  // Get current date on mount
  const currentDate = useMemo(() => new Date(), []);
  const formattedDate = format(currentDate, 'EEEE, MMMM d, yyyy');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [projectsData, commsData] = await Promise.all([
          projectsApi.getAll(),
          communicationsApi.getAll()
        ]);
        setProjects(projectsData);
        setCommunications(commsData);
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const activeProjects = projects.filter(p => p.fieldValues['/attributes/@stat3'] === 'opt-active');
  const completedProjects = projects.filter(p => p.fieldValues['/attributes/@stat3'] === 'opt-complete');
  const unreadMessages = communications.filter(c => c.fieldValues['/attributes/@read3'] === 'opt-unread');

  const avgProgress = projects.length > 0 
    ? Math.round(projects.reduce((sum, p) => sum + (p.fieldValues['/attributes/@prog4'] || 0), 0) / projects.length)
    : 0;

  const stats = [
    {
      label: 'Active Projects',
      value: activeProjects.length,
      icon: FolderOpen,
      color: 'bg-blue-600',
      bgColor: 'bg-blue-500/10',
    },
    {
      label: 'Avg Progress',
      value: `${avgProgress}%`,
      icon: BarChart3,
      color: 'bg-purple-600',
      bgColor: 'bg-purple-500/10',
    },
    {
      label: 'Unread Messages',
      value: unreadMessages.length,
      icon: Mail,
      color: 'bg-amber-600',
      bgColor: 'bg-amber-500/10',
    },
    {
      label: 'Completed',
      value: completedProjects.length,
      icon: CheckCircle2,
      color: 'bg-emerald-600',
      bgColor: 'bg-emerald-500/10',
    },
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Header */}
      <div className="text-center">
        <h1 className="text-3xl lg:text-4xl font-bold text-foreground tracking-tight">
          🗓️ {formattedDate}
        </h1>
        <p className="text-muted-foreground mt-1.5 text-sm">Here's what's happening</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3.5">
        {stats.map((stat, index) => {
          const hasValue = stat.value > 0;
          return (
            <div
              key={stat.label}
              className={cn(
                'p-5 rounded-xl group',
                'bg-card/80 backdrop-blur-sm border border-border',
                'hover:bg-card hover:border-border/80 transition-all duration-200',
                hasValue && 'hover:shadow-xl hover:shadow-primary/10'
              )}
            >
              <div className="flex items-start justify-between">
                <div>
                  <p className="text-muted-foreground text-xs">{stat.label}</p>
                  <p className="text-2xl font-bold text-foreground mt-1.5 tracking-tight">{stat.value}</p>
                </div>
                <div className={cn('p-2.5 rounded-lg', stat.color, 'group-hover:scale-105 transition-transform duration-200')}>
                  <stat.icon className="w-4 h-4 text-white" />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Active Projects - 2x3 Grid */}
      <div className="p-5 rounded-xl bg-card/80 backdrop-blur-sm border border-border">
        <div className="flex items-center gap-2.5 mb-5">
          <Folder className="w-4 h-4 text-primary" />
          <h2 className="text-lg font-semibold text-foreground tracking-tight">Active Projects</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
          {activeProjects.slice(0, 6).map((project, index) => {
            const progress = project.fieldValues['/attributes/@prog4'] || 0;
            const status = project.fieldValues['/attributes/@stat3'];
            const progressColor = progressColors[index % progressColors.length];

            return (
              <div
                key={project.id}
                className={cn(
                  'p-3.5 rounded-xl',
                  'bg-card/70 border border-border/70',
                  'hover:bg-card hover:border-border hover:shadow-lg hover:shadow-primary/10',
                  'transition-all duration-200'
                )}
              >
                <div className="space-y-2.5">
                  <div>
                    <h3 className="font-medium text-foreground text-sm line-clamp-1">
                      {project.fieldValues['/attributes/@proj2'] || project.fieldValues['/text']}
                    </h3>
                    <p className="text-xs text-muted-foreground mt-0.5 line-clamp-1">
                      {project.fieldValues['/attributes/@cli01']}
                    </p>
                  </div>

                  {/* Compact Progress Bar */}
                  <div className="space-y-1">
                    <div className="flex justify-between text-[10px] text-muted-foreground">
                      <span>Progress</span>
                      <span className="font-medium">{progress}%</span>
                    </div>
                    <div className="h-1.5 bg-muted rounded-full overflow-hidden">
                      <div
                        style={{ width: `${progress}%` }}
                        className={cn('h-full rounded-full', progressColor)}
                      />
                    </div>
