          })}

          {activeProjects.length === 0 && (
            <div className="col-span-full text-center text-muted-foreground py-8">
              No active projects
            </div>
          )}
        </div>
      </div>

      {/* Recent Messages - Three Columns */}
      <div className="p-5 rounded-xl bg-card/80 backdrop-blur-sm border border-border">
        <div className="flex items-center gap-2.5 mb-5">
          <Mail className="w-4 h-4 text-primary" />
          <h2 className="text-lg font-semibold text-foreground tracking-tight">Recent Messages</h2>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-border/50">
                <th className="text-left text-xs font-medium text-muted-foreground uppercase tracking-wider pb-3 px-3">
                  Date
                </th>
                <th className="text-left text-xs font-medium text-muted-foreground uppercase tracking-wider pb-3 px-3">
                  Sender
                </th>
                <th className="text-left text-xs font-medium text-muted-foreground uppercase tracking-wider pb-3 px-3">
                  Message
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border/30">
              {communications.slice(0, 5).map((comm, index) => {
                const isUnread = comm.fieldValues['/attributes/@read3'] === 'opt-unread';

                return (
                  <tr
                    key={comm.id}
                    className={cn(
                      'hover:bg-accent/30 transition-colors duration-150',
                      isUnread && 'bg-primary/5'
                    )}
                  >
                    <td className="py-3 px-3 text-sm text-muted-foreground whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {isUnread && (
                          <div className="w-1.5 h-1.5 bg-primary rounded-full flex-shrink-0" />
                        )}
                        <span>Today</span>
                      </div>
                    </td>
                    <td className="py-3 px-3 text-sm text-foreground font-medium">
                      {comm.fieldValues['/attributes/@from8']}
                    </td>
                    <td className="py-3 px-3 text-sm text-muted-foreground">
                      <div className="max-w-md">
                        <p className="font-medium text-foreground mb-0.5 line-clamp-1">
                          {comm.fieldValues['/attributes/@subj0']}
                        </p>
                        <p className="line-clamp-1">
                          {comm.fieldValues['/attributes/@msg11']}
                        </p>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          {communications.length === 0 && (
            <div className="text-center text-muted-foreground py-12">
              <Mail className="w-12 h-12 mx-auto mb-3 opacity-20" />
              <p>No messages</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { useAgentChat } from '../lib/agent-chat';
import { MessageCircle, X, Send, Loader2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '../lib/utils';

const AGENT_ID = '01KN6ZK3QN7TGTD1P2GJF5807C';

export function PortalAssistant() {
  const [isOpen, setIsOpen] = useState(false);
  const [conversationId, setConversationId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isInitializing, setIsInitializing] = useState(false);
  const hasAnimatedRef = useRef(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const {
    sendMessage,
    messages,
    isConnected,
    createConversation: createNewConversation,
    error
  } = useAgentChat(AGENT_ID, conversationId);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleStartChat = async () => {
    setIsInitializing(true);
    const newConvoId = await createNewConversation();
    setConversationId(newConvoId);
    setIsInitializing(false);
  };

  const handleSendMessage = async (messageText?: string) => {
    const textToSend = messageText || inputValue.trim();
    if (!textToSend || !conversationId) return;

    await sendMessage(textToSend);
    setInputValue('');
  };

  const handleStarterClick = async (prompt: string) => {
    if (!conversationId) return;
    await handleSendMessage(prompt);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  useEffect(() => {
    if (isOpen && !conversationId && !isInitializing) {
      handleStartChat();
    }
  }, [isOpen]);

  return (
    <>
      {/* Floating Button */}
      <motion.button
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setIsOpen(!isOpen)}
        className={cn(
          'fixed bottom-6 right-6 z-50',
          'w-14 h-14 rounded-full',
          'bg-purple-600',
          'backdrop-blur-lg border border-white/20',
          'shadow-lg shadow-blue-500/20',
          'flex items-center justify-center',
          'transition-all duration-300'
        )}
      >
        <AnimatePresence mode="wait">
          {isOpen ? (
            <motion.div
              key="close"
              initial={{ rotate: -90, opacity: 0 }}
              animate={{ rotate: 0, opacity: 1 }}
              exit={{ rotate: 90, opacity: 0 }}
            >
              <X className="w-6 h-6 text-white" />
            </motion.div>
          ) : (
            <motion.div
              key="open"
              initial={{ rotate: 90, opacity: 0 }}
              animate={{ rotate: 0, opacity: 1 }}
              exit={{ rotate: -90, opacity: 0 }}
            >
              <MessageCircle className="w-6 h-6 text-white" />
            </motion.div>
          )}
        </AnimatePresence>
      </motion.button>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && !isInitializing && conversationId && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className={cn(
              'fixed bottom-24 right-6 z-40',
              'w-96 h-[600px]',
              'rounded-2xl',
              'bg-card/95 dark:bg-card/90',
              'backdrop-blur-xl border border-border',
              'shadow-2xl',
              'flex flex-col overflow-hidden'
            )}
          >
            {/* Header */}
            <div className="p-4 border-b border-border bg-gradient-to-r from-primary/10 to-primary/5">
              <h3 className="font-semibold text-foreground">Portal Assistant</h3>
              <p className="text-xs text-muted-foreground mt-1">
                {isConnected ? '✓ Connected' : 'Connecting...'}
              </p>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {messages.length === 0 && (
                <div className="space-y-6 mt-4">
                  <div className="text-center text-muted-foreground text-sm">
                    <p className="text-base font-medium text-foreground">Hello! I'm your Portal Assistant.</p>
                    <p className="mt-1.5">I can help you with projects, files, and messages.</p>
                  </div>

                  {/* Conversation Starters */}
                  <div className="space-y-2">
                    <p className="text-xs text-muted-foreground font-medium px-1">Quick actions:</p>
                    <div className="grid grid-cols-1 gap-2">
                      {[
                        { id: "starter-1", title: "Show my active projects", prompt: "What are my active projects?" },
                        { id: "starter-2", title: "Check unread messages", prompt: "Do I have any unread messages?" },
                        { id: "starter-3", title: "View recent files", prompt: "Show me my recent files" },
                        { id: "starter-4", title: "Project status summary", prompt: "Give me a summary of all project statuses" }
                      ].map((starter, index) => {
                        // Mark as animated on first render
                        if (!hasAnimatedRef.current) {
                          hasAnimatedRef.current = true;
                        }

                        return (
                          <button
                            key={starter.id}
                            onClick={() => handleStarterClick(starter.prompt)}
                            disabled={!conversationId}
                            style={{
                              animationDelay: hasAnimatedRef.current ? '0ms' : `${index * 50}ms`
                            }}
                            className={cn(
                              'p-3 rounded-lg text-left',
                              'bg-accent/50 hover:bg-accent',
                              'border border-border/50 hover:border-border',
                              'text-sm text-foreground',
                              'transition-all duration-200',
                              'hover:shadow-md hover:scale-[1.01]',
                              'disabled:opacity-50 disabled:cursor-not-allowed',
                              !hasAnimatedRef.current && 'animate-in fade-in slide-in-from-bottom-2'
                            )}
                          >
                            {starter.title}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                </div>
              )}

              {messages.map((msg) => (
                <motion.div
                  key={msg.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={cn(
                    'flex',
                    msg.role === 'user' ? 'justify-end' : 'justify-start'
                  )}
                >
                  <div
                    className={cn(
                      'max-w-[80%] px-4 py-2 rounded-2xl',
                      msg.role === 'user'
                        ? 'bg-gradient-to-br from-blue-500 to-purple-600 text-white'
                        : 'bg-muted text-foreground border border-border'
                    )}
                  >
                    <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                    {msg.toolCalls && msg.toolCalls.length > 0 && (
                      <div className="mt-2 pt-2 border-t border-white/10">
                        <p className="text-xs opacity-60">
                          🔧 Using {msg.toolCalls.length} tool{msg.toolCalls.length > 1 ? 's' : ''}
                        </p>
                      </div>
                    )}
                  </div>
                </motion.div>
              ))}

              {error && (
                <div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm">
                  Error: {error}
                </div>
              )}

              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 border-t border-border bg-card/50">
              <div className="flex gap-2">
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyPress={handleKeyPress}
                  placeholder="Ask me anything..."
                  disabled={!conversationId}
                  className={cn(
                    'flex-1 px-4 py-2 rounded-xl',
                    'bg-background border border-border',
                    'text-foreground placeholder-muted-foreground',
                    'focus:outline-none focus:ring-2 focus:ring-ring',
                    'disabled:opacity-50 disabled:cursor-not-allowed'
                  )}
                />
                <button
                  onClick={handleSendMessage}
                  disabled={!conversationId || !inputValue.trim()}
                  className={cn(
                    'px-4 py-2 rounded-xl',
                    'bg-gradient-to-br from-blue-500 to-purple-600',
                    'text-white font-medium',
                    'disabled:opacity-50 disabled:cursor-not-allowed',
                    'hover:shadow-lg hover:shadow-primary/20',
                    'transition-all duration-200',
                    'flex items-center justify-center'
                  )}
                >
                  {!conversationId ? (
                    <Loader2 className="w-5 h-5 animate-spin" />
                  ) : (
                    <Send className="w-5 h-5" />
                  )}
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

import { useMemo } from 'react';

interface Particle {
  id: number;
  size: number;
  left: number;
  duration: number;
  delay: number;
  opacity: number;
}

export function FloatingParticles() {
  const particles = useMemo(() => {
    const particleArray: Particle[] = [];
    // Generate 25 particles for vivid effect
    for (let i = 0; i < 25; i++) {
      particleArray.push({
        id: i,
        size: Math.random() * 5 + 4, // 4-9px (larger)
        left: Math.random() * 100, // 0-100%
        duration: Math.random() * 15 + 20, // 20-35s (slower)
        delay: Math.random() * -25, // stagger start
        opacity: Math.random() * 0.3 + 0.7, // 0.7-1.0 (maximum brightness)
      });
    }
    return particleArray;
  }, []);

  return (
    <div className="fixed inset-0 overflow-hidden pointer-events-none">
      {particles.map((particle) => (
        <div
          key={particle.id}
          className="absolute bottom-0 rounded-full bg-gradient-to-t from-blue-300 via-purple-300 to-pink-300 dark:from-cyan-200 dark:via-violet-200 dark:to-fuchsia-200 animate-float-up"
          style={{
            width: `${particle.size}px`,
            height: `${particle.size}px`,
            left: `${particle.left}%`,
            opacity: particle.opacity,
            animationDuration: `${particle.duration}s`,
            animationDelay: `${particle.delay}s`,
            boxShadow: '0 0 16px currentColor, 0 0 32px currentColor, 0 0 48px currentColor',
            filter: 'brightness(1.5)',
          }}
        />
      ))}
    </div>
  );
}
